def associa_numeri():
    risultati = []
    n = 1
    for a in range(100):
        for s in range(5):
            partenza = films[a][2]
            anno_cas = random.randint(partenza, 2023)
            risultati.append((anno_cas, random.randint(1, 5), random.randint(1, 10), random.randint(1, 5), n, a+1))
            n = n+1
    return risultati

def stampa_risultati(risultati):
    for anno, dimensione, video, audio, versione, film  in risultati:
        print(f'({anno}, {dimensione}, {video}, {audio}, {versione}, {film}),', end="")

if __name__ == "__main__":
    result = associa_numeri()
    stampa_risultati(result)